import React, { useState, useContext } from 'react';
import { View, Text, TextInput, Button, StyleSheet } from 'react-native';
import HoverableButton from '../components/HoverableButton';
import theme from '../theme';
import { AppContext } from '../context/AppContext';

export default function LoginScreen({ navigation }) {
  const [email, setEmail] = useState('alice@example.com');
  const [name, setName] = useState('Alice');
  const { login } = useContext(AppContext);

  const handleLogin = () => {
    login(email, name);
    navigation.replace('Home');
  };

  return (
    <View style={[styles.container, { backgroundColor: theme.background }] }>
      <View style={styles.card}>
        <Text style={styles.title}>Log-in</Text>
        <TextInput style={styles.input} value={name} onChangeText={setName} placeholder="Name" />
        <TextInput style={styles.input} value={email} onChangeText={setEmail} placeholder="Email" keyboardType="email-address" />
        <HoverableButton style={styles.loginBtn} onPress={handleLogin}>
          <Text style={styles.loginText}>Login</Text>
        </HoverableButton>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', padding: 20 },
  card: { backgroundColor: '#fff', padding: 28, borderRadius: 12, marginHorizontal: 12, shadowColor: '#000', shadowOpacity: 0.03, shadowRadius: 8 },
  title: { fontSize: 22, marginBottom: 20, textAlign: 'center', color: theme.textPrimary, fontWeight: '600' },
  input: { borderWidth: 1, borderColor: theme.border, padding: 12, marginBottom: 12, borderRadius: 8, backgroundColor: '#fff' },
  loginBtn: { backgroundColor: theme.primary, paddingVertical: 12, borderRadius: 8, alignItems: 'center' },
  loginText: { color: theme.buttonText, fontWeight: '700' }
});
